int minimumEnergyToReachLastRooftop(int n, int k, int heights[]) {
    int *dp = (int *)malloc(n * sizeof(int));

    for (int i = 0; i < n; i++)
        dp[i] = INT_MAX;

    dp[0] = 0;

    for (int i = 1; i < n; i++) {
        for (int j = 1; j <= k; j++) {
            if (i - j >= 0) {
                int energy = dp[i - j] + abs(heights[i] - heights[i - j]);
                if (energy < dp[i]) {
                    dp[i] = energy;
                }
            }
        }
    }

    int result = dp[n - 1];
    free(dp);
    return result;
}

